// Extract the last user message from OpenAI chat format
// LibreChat sends: { model, messages: [{role, content}], stream, ... }
const body = $json.body || $json;
const messages = body.messages || [];

// Get the last user message
const lastUserMsg = [...messages].reverse().find(m => m.role === 'user');
const userText = (typeof lastUserMsg?.content === 'string' 
  ? lastUserMsg.content 
  : lastUserMsg?.content?.[0]?.text || '').toLowerCase().trim();

// Detect ICP / document generation intent
const icpKeywords = [
  'generate icp', 'create icp', 'icp report', 'icp review',
  'quarterly review', 'quarterly report', 'client review',
  'generate report', 'create report', 'build report',
  'generate document', 'create document'
];

const isICP = icpKeywords.some(kw => userText.includes(kw));

console.log('[DAX-ROUTER] Message:', userText.substring(0, 100));
console.log('[DAX-ROUTER] Route:', isICP ? 'ICP' : 'GENERAL');

return [{
  json: {
    route: isICP ? 'ICP' : 'GENERAL',
    userMessage: lastUserMsg?.content || '',
    userText,
    originalBody: body,
    messages
  }
}];

// Build n8n document generator payload from extracted fields
const agentOutput = $('ICP Field Extractor').first().json.output || '{}';
const routeData = $('Route Input').first().json;

let fields = {};
try {
  const jsonMatch = agentOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) fields = JSON.parse(jsonMatch[0]);
} catch(e) {
  console.log('[DAX-ROUTER] Parse error:', e.message);
}

// Check if we have minimum required fields
if (!fields.clientName) {
  // Need to ask for more info - return a clarification response
  return [{
    json: {
      needsClarification: true,
      message: "I'd be happy to generate an ICP report! Could you provide the client's name and the report period (e.g. Q1 2026)?"
    }
  }];
}

const now = new Date();
const reportDate = now.toISOString().split('T')[0];

return [{
  json: {
    needsClarification: false,
    firmName: fields.firmName || 'Dakona Advisory',
    clientName: fields.clientName,
    reportPeriod: fields.reportPeriod || 'Q1 2026',
    reportDate: fields.reportDate || reportDate,
    advisorName: fields.advisorName || 'Your Advisor',
    accountNumber: fields.accountNumber || 'TBD',
    accountType: fields.accountType || 'Investment Account',
    riskProfile: fields.riskProfile || 'Moderate',
    meetingDate: fields.meetingDate || reportDate,
    meetingLocation: fields.meetingLocation || 'Zoom',
    attendees: fields.attendees || fields.advisorName || 'Advisor',
    meetingDuration: fields.meetingDuration || '60 min',
    discussionPoint1: fields.discussionPoint1 || '',
    discussionPoint2: fields.discussionPoint2 || '',
    discussionPoint3: fields.discussionPoint3 || '',
    advisorNotes: fields.advisorNotes || '',
    portfolioValue: fields.portfolioValue || 'TBD',
    ytdReturn: fields.ytdReturn || 'TBD',
    benchmarkReturn: fields.benchmarkReturn || 'TBD',
    vsBenchmark: fields.vsBenchmark || 'TBD',
    goal1: fields.goal1 || '',
    goal2: fields.goal2 || '',
    goal3: fields.goal3 || '',
    goalsProgressNotes: fields.goalsProgressNotes || '',
    action1: fields.action1 || '',
    action1Owner: fields.action1Owner || '',
    action1Due: fields.action1Due || '',
    action2: fields.action2 || '',
    action2Owner: fields.action2Owner || '',
    action2Due: fields.action2Due || '',
    action3: fields.action3 || '',
    action3Owner: fields.action3Owner || '',
    action3Due: fields.action3Due || '',
    nextMeetingDate: fields.nextMeetingDate || '',
    nextMeetingAgenda: fields.nextMeetingAgenda || ''
  }
}];

// Format response as OpenAI-compatible chat completion
const docResult = $('Generate Document').first().json;
const payload = $('Build Document Payload').first().json;

const now = Math.floor(Date.now() / 1000);

let content;
if (docResult?.webUrl) {
  content = `✅ Your ${payload.reportPeriod} ICP report for **${payload.clientName}** is ready!\n\n📄 [Open in SharePoint](${docResult.webUrl})\n\nThe document has been saved to the ${payload.clientName} folder in SharePoint.`;
} else {
  content = `I attempted to generate the ICP report for ${payload.clientName} but encountered an issue. Please try again or contact support.`;
}

// Write audit log to Cosmos would go here in future

return [{
  json: {
    id: 'chatcmpl-dax-' + now,
    object: 'chat.completion',
    created: now,
    model: 'gpt-4o',
    choices: [{
      index: 0,
      message: {
        role: 'assistant',
        content: content
      },
      finish_reason: 'stop'
    }],
    usage: {
      prompt_tokens: 100,
      completion_tokens: 50,
      total_tokens: 150
    }
  }
}];
